}

using System;
using System.Net.Http;
using System.Threading.Tasks;

class Program {
    static async Task Main() {
        using var client = new HttpClient();
        HttpResponseMessage response = await client.GetAsync("https://httpbin.org/status/200");
        Console.WriteLine((int)response.StatusCode);
        Console.WriteLine(response.IsSuccessStatusCode);
    }
}

using System;
using System.Text.Json;

record WeatherData(string City, double TempC, string Condition);

class Program {
    static void Main() {
        string json = """{"City":"London","TempC":15.5,"Condition":"Cloudy"}""";
        var weather = JsonSerializer.Deserialize<WeatherData>(json,
            new JsonSerializerOptions { PropertyNameCaseInsensitive = true });
        Console.WriteLine($"{weather.City}: {weather.TempC}C, {weather.Condition}");
    }
}

using System;
using System.Text.Json;

record User(int Id, string Name, string Email);

class Program {
    static void Main() {
        var user = new User(1, "Alice", "alice@example.com");
        string json = JsonSerializer.Serialize(user,
            new JsonSerializerOptions { WriteIndented = true });
        Console.WriteLine(json);
    }
}

using System;
using System.Net.Http;
using System.Net.Http.Json;
using System.Threading.Tasks;

record Todo(string Title, bool Completed);

class Program {
    static async Task Main() {
        using var client = new HttpClient();
        var todo = new Todo("Learn C#", false);
        var response = await client.PostAsJsonAsync(
            "https://jsonplaceholder.typicode.com/todos", todo);
        Console.WriteLine(response.StatusCode);
    }
}

using System;
using System.Net.Http;
using System.Threading.Tasks;

static async Task FetchSafely(string url) {
    using var client = new HttpClient();
    try {
        var response = await client.GetAsync(url);
        response.EnsureSuccessStatusCode();
        Console.WriteLine($"{(int)response.StatusCode}: success");
    } catch (HttpRequestException ex) {
        Console.WriteLine($"HTTP error: {ex.StatusCode}");
    } catch (Exception ex) {
        Console.WriteLine($"Error: {ex.Message}");
    }
}

class Program {
    static async Task Main() {
        await FetchSafely("https://httpbin.org/status/200");
        await FetchSafely("https://httpbin.org/status/404");
    }
}

using System;
using System.Net.Http;
using System.Threading.Tasks;
using System.Web;

class Program {
    static async Task Main() {
        using var client = new HttpClient();
        client.DefaultRequestHeaders.Add("Accept", "application/json");

        var query = HttpUtility.ParseQueryString(string.Empty);
        query["userId"] = "1";
        string url = $"https://jsonplaceholder.typicode.com/todos?{query}";
        Console.WriteLine(url);

        var response = await client.GetAsync(url);
        Console.WriteLine($"status: {(int)response.StatusCode}");
    }
}
